    final String displayName;
    final EquipmentType type;
    final int[] requirements;
    final int[] bonuses;
    final boolean hasNegativeBonus;

    private Equipment(String displayName, EquipmentType type, int[] requirements, int[] bonuses) {
        this.displayName = displayName;
        this.type = type;
        this.requirements = requirements;
        this.bonuses = bonuses;
        this.hasNegativeBonus = checkNegativeBonus(bonuses);
    }

    @Override
    public EquipmentType type() {
        return type;
    }

    @Override
    public int[] requirements() {
        return requirements;
    }

    @Override
    public int[] bonuses() {
        return bonuses;
    }

    @Override
    public boolean hasNegativeBonus() {
        return hasNegativeBonus;
    }

    @Override
    public boolean canEquip(IPlayer player) {
        // Not using an enhanced for here to save allocations!
        for (int i = 0; i < requirements.length; i++) {
            int requirement = requirements[i];
            if (requirement <= 0 || player.total(SKILL_POINTS[i]) >= requirement) {
                continue;
            }

            return false;
        }

        return true;
    }

    @Override
    public String toString() {
        return String.format("%s (req: %s) (bonus: %s)", displayName, Arrays.toString(requirements), Arrays.toString(bonuses));
    }

